content.text:
// Response from your REST endpoint — B2C merges these claims into the token
{
  "version": "1.0.0",
  "action": "Continue",
  "extension_loyaltyTier": "Gold",
  "extension_accountRegion": "EMEA"
}

// To block the request and show an error page:
{
  "version": "1.0.0",
  "action": "ShowBlockPage",
  "userMessage": "Your account is not yet approved. Contact support@contoso.com."
}

// To show inline validation errors on the sign-up form:
{
  "version": "1.0.0",
  "action": "ValidationError",
  "status": 400,
  "userMessage": "This email domain is not allowed to register."
}

terraform {
  required_providers {
    azapi = {
      source  = "azure/azapi"
      version = "~> 1.12"
    }
  }
}

# Create a Sign-up and Sign-in user flow using azapi
resource "azapi_resource" "susi_flow" {
  type      = "Microsoft.AzureActiveDirectory/b2cDirectories/userFlows@2019-01-01-preview"
  name      = "B2C_1_SignUpSignIn"
  parent_id = "/subscriptions/${var.subscription_id}/resourceGroups/${var.rg}/providers/Microsoft.AzureActiveDirectory/b2cDirectories/${var.b2c_domain}"
  body = jsonencode({
    properties = {
      userFlowType        = "signUpOrSignIn"
      userFlowTypeVersion = 2
    }
  })
}

variable "subscription_id" {}
variable "rg"              {}
variable "b2c_domain"      {}
